import React, { useState, useEffect } from "react";
import axios from "axios";
import { VerticalGraph } from "./components/VerticalGraph";

const Holdings = () => {
  const [allHoldings, setAllHoldings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchHoldings = async () => {
      try {
        const res = await axios.get(
          `${process.env.REACT_APP_API_URL || "http://localhost:3002"}/allHoldings`
        );
        setAllHoldings(res.data);
      } catch (err) {
        console.error("Failed to fetch holdings:", err);
        setError("Failed to load holdings.");
      } finally {
        setLoading(false);
      }
    };

    fetchHoldings();
  }, []);

  // Portfolio Calculations
  const totalInvestment = allHoldings.reduce(
    (acc, stock) => acc + stock.avg * stock.qty,
    0
  );

  const totalCurrentValue = allHoldings.reduce(
    (acc, stock) => acc + stock.price * stock.qty,
    0
  );

  const totalPnL = totalCurrentValue - totalInvestment;
  const totalPnLPercent =
    totalInvestment > 0 ? (totalPnL / totalInvestment) * 100 : 0;

  const totalClass = totalPnL >= 0 ? "profit" : "loss";

  // Graph Data
  const labels = allHoldings.map((stock) => stock.name);

  const data = {
    labels,
    datasets: [
      {
        label: "Stock Price",
        data: allHoldings.map((stock) => stock.price),
        backgroundColor: "rgba(255, 99, 132, 0.5)",
      },
    ],
  };

  const formatCurrency = (value) =>
    value.toLocaleString("en-IN", {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    });

  if (loading) return <p>Loading holdings...</p>;
  if (error) return <p className="error">{error}</p>;

  return (
    <>
      <h3 className="title">Holdings ({allHoldings.length})</h3>

      <div className="order-table">
        <table>
          <thead>
            <tr>
              <th>Instrument</th>
              <th>Qty.</th>
              <th>Avg. cost</th>
              <th>LTP</th>
              <th>Cur. val</th>
              <th>P&L</th>
              <th>Net chg.</th>
              <th>Day chg.</th>
            </tr>
          </thead>

          <tbody>
            {allHoldings.map((stock) => {
              const currentValue = stock.price * stock.qty;
              const pnl = currentValue - stock.avg * stock.qty;
              const profClass = pnl >= 0 ? "profit" : "loss";
              const dayClass = stock.isLoss ? "loss" : "profit";

              return (
                <tr key={stock.name}>
                  <td>{stock.name}</td>
                  <td>{stock.qty}</td>
                  <td>₹{formatCurrency(stock.avg)}</td>
                  <td>₹{formatCurrency(stock.price)}</td>
                  <td>₹{formatCurrency(currentValue)}</td>
                  <td className={profClass}>₹{formatCurrency(pnl)}</td>
                  <td className={profClass}>{stock.net}</td>
                  <td className={dayClass}>{stock.day}</td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* Portfolio Summary */}
      <div className="row">
        <div className="col">
          <h5>₹{formatCurrency(totalInvestment)}</h5>
          <p>Total investment</p>
        </div>

        <div className="col">
          <h5>₹{formatCurrency(totalCurrentValue)}</h5>
          <p>Current value</p>
        </div>

        <div className="col">
          <h5 className={totalClass}>
            ₹{formatCurrency(totalPnL)} ({totalPnLPercent.toFixed(2)}%)
          </h5>
          <p>P&L</p>
        </div>
      </div>

      <VerticalGraph data={data} />
    </>
  );
};

export default Holdings;
